const items = $input.all();
let business;
try { business = $('Loop Over Businesses1').item.json; }
catch (e) { business = $('Loop Over Businesses1').first().json; }

const pageData = items[0]?.json || {};
const html = String(pageData.html || pageData.text || pageData.markdown || pageData.content || '');
const meta = pageData.metadata || {};
const socialLinks = meta.socialLinks || pageData.socialLinks || {};

let facebookUrl  = socialLinks.facebook  || socialLinks.fb  || '';
let instagramUrl = socialLinks.instagram || socialLinks.ig  || '';
let youtubeUrl   = socialLinks.youtube   || socialLinks.yt  || '';

const FB_JUNK = new Set(['sharer','sharer.php','share','share.php','tr','plugins','dialog','login','help','policies','privacy','terms','campaign','connect','watch','gaming']);
const IG_JUNK = new Set(['p','reel','reels','tv','explore','stories','accounts','about','developer','legal','embed','privacy','terms','graphql','api']);
const YT_JUNK = new Set(['watch','results','feed','playlist','shorts','trending','premium','about','terms','privacy','music']);

function findAll(html, host) {
  const re = new RegExp('https?://(?:www\\.)?' + host + '/[^"\'\\s<>)\\\\]+', 'gi');
  return html.match(re) || [];
}
function firstSeg(url, host) {
  const after = url.split(new RegExp(host + '/', 'i'))[1] || '';
  return after.split('?')[0].split('#')[0].split('/').filter(Boolean);
}

if (!facebookUrl) {
  const raws = [...findAll(html, 'facebook\\.com'), ...findAll(html, 'fb\\.com')];
  for (const raw of raws) {
    const prof = raw.match(/facebook\.com\/profile\.php\?id=\d+/i);
    if (prof) { facebookUrl = 'https://www.' + prof[0]; break; }
    const seg = firstSeg(raw, 'facebook\\.com').length ? firstSeg(raw, 'facebook\\.com') : firstSeg(raw, 'fb\\.com');
    const first = (seg[0] || '').toLowerCase();
    if (!first || FB_JUNK.has(first)) continue;
    facebookUrl = first === 'pages' && seg.length >= 2 ? 'https://www.facebook.com/' + seg.join('/') : 'https://www.facebook.com/' + seg[0];
    break;
  }
}
if (!instagramUrl) {
  for (const raw of findAll(html, 'instagram\\.com')) {
    const seg = firstSeg(raw, 'instagram\\.com');
    const first = (seg[0] || '').toLowerCase();
    if (!first || IG_JUNK.has(first)) continue;
    instagramUrl = 'https://www.instagram.com/' + seg[0]; break;
  }
}
if (!youtubeUrl) {
  for (const raw of findAll(html, 'youtube\\.com')) {
    const seg = firstSeg(raw, 'youtube\\.com');
    const first = (seg[0] || '').toLowerCase();
    if (!first || YT_JUNK.has(first)) continue;
    youtubeUrl = 'https://www.youtube.com/' + seg[0]; break;
  }
}

return [{ json: { id: business.id, name: business.name, placeid: business.placeid, facebookurl: facebookUrl, instagramurl: instagramUrl, youtubeurl: youtubeUrl, source: 'apify_website' } }];

const items = $input.all();
let business;
try { business = $('Loop Over Businesses1').item.json; }
catch (e) { business = $('Loop Over Businesses1').first().json; }

const results = items.map(i => i.json).flat();

let facebookUrl = '', instagramUrl = '', youtubeUrl = '';
const FB_JUNK = new Set(['sharer','share','tr','plugins','dialog','login','help','policies','privacy','terms','watch','gaming']);
const IG_JUNK = new Set(['p','reel','reels','explore','accounts','about','legal','privacy','terms']);
const YT_JUNK = new Set(['watch','results','feed','playlist','shorts','trending','premium','about','terms','privacy']);

function firstSeg(url, host) {
  const after = url.split(new RegExp(host + '/', 'i'))[1] || '';
  return after.split('?')[0].split('#')[0].split('/').filter(Boolean);
}

const allUrls = [];
for (const r of results) {
  if (r.url) allUrls.push(r.url);
  if (r.displayUrl) allUrls.push(r.displayUrl);
  const desc = r.description || r.snippet || '';
  const matches = desc.match(/https?:\/\/(?:www\.)?(?:facebook|instagram|youtube)\.com\/[^\s"'<>]+/gi) || [];
  allUrls.push(...matches);
}

for (const url of allUrls) {
  if (!facebookUrl && /facebook\.com/i.test(url)) {
    const seg = firstSeg(url, 'facebook\\.com');
    const first = (seg[0] || '').toLowerCase();
    if (first && !FB_JUNK.has(first)) facebookUrl = 'https://www.facebook.com/' + seg[0];
  }
  if (!instagramUrl && /instagram\.com/i.test(url)) {
    const seg = firstSeg(url, 'instagram\\.com');
    const first = (seg[0] || '').toLowerCase();
    if (first && !IG_JUNK.has(first)) instagramUrl = 'https://www.instagram.com/' + seg[0];
  }
  if (!youtubeUrl && /youtube\.com/i.test(url)) {
    const seg = firstSeg(url, 'youtube\\.com');
    const first = (seg[0] || '').toLowerCase();
    if (first && !YT_JUNK.has(first)) youtubeUrl = 'https://www.youtube.com/' + seg[0];
  }
  if (facebookUrl && instagramUrl && youtubeUrl) break;
}

return [{ json: { id: business.id, name: business.name, placeid: business.placeid, facebookurl: facebookUrl, instagramurl: instagramUrl, youtubeurl: youtubeUrl, source: 'apify_google_search' } }];

// Skip Supabase update if absolutely nothing was found
// This prevents overwriting existing data with empty strings
const d = $input.first().json;
let existing;
try { existing = $('Loop Over Businesses1').item.json; }
catch(e) { existing = {}; }

const hasSomething = d.facebookurl || d.instagramurl || d.youtubeurl || 
                     existing.facebookurl || existing.instagramurl || existing.youtubeurl;

if (!hasSomething) {
  // Nothing at all — skip update, go straight to loop
  return [{ json: { ...d, skipUpdate: true } }];
}

return [{ json: { ...d, skipUpdate: false } }];

const items = $input.all();
return items.map(item => {
  const d = item.json;
  // Get existing values from Supabase (original business data)
  let existing;
  try { existing = $('Loop Over Businesses1').item.json; }
  catch(e) { existing = {}; }

  // Only update a field if new value was found — keep old value otherwise
  return {
    json: {
      id:           d.id,
      name:         d.name,
      placeid:      d.placeid,
      facebookurl:  d.facebookurl  || existing.facebookurl  || '',
      instagramurl: d.instagramurl || existing.instagramurl || '',
      youtubeurl:   d.youtubeurl   || existing.youtubeurl   || '',
      source:       d.source
    }
  };
});

const item = $input.first().json;
console.log(`Done: ${item.name} | FB: ${item.facebookurl||'-'} | IG: ${item.instagramurl||'-'} | YT: ${item.youtubeurl||'-'}`);
return $input.all();

